arguments.command:
$REPO = "edburns/Build26-BRK206-your-agent-anywhere-multiclient-multidevice-with-github-copilot-sdk"
$PR_NUMBER = "19"
$JTBDTASK_BRANCH = "copilot/dd-3017826-websocket-driven-ui-update"

Write-Host "Waiting for CCA run to complete..."

$TIMEOUT = 900
$INTERVAL = 30
$ELAPSED = 0

while ($ELAPSED -lt $TIMEOUT) {
    $runs = gh run list -R $REPO --branch "$JTBDTASK_BRANCH" --json databaseId,name,status,conclusion --limit 10 | ConvertFrom-Json

    $inProgress = $runs | Where-Object { $_.status -eq "in_progress" -or $_.status -eq "queued" -or $_.status -eq "waiting" }
    $actionRequired = $runs | Where-Object { $_.conclusion -eq "action_required" }

    Write-Host "[${ELAPSED}s] in_progress: $($inProgress.Count), action_required: $($actionRequired.Count)"
    $runs | ForEach-Object { Write-Host "  - $($_.name): $($_.status)/$($_.conclusion)" }

    if ($inProgress.Count -eq 0) {
        Write-Host "All runs completed or waiting for approval."
        break
    }

    Start-Sleep -Seconds $INTERVAL
    $ELAPSED += $INTERVAL
}

Write-Host "Final run state:"
gh run list -R $REPO --branch "$JTBDTASK_BRANCH" --json databaseId,name,status,conclusion --limit 10

